import React from 'react';
import { useParams } from 'react-router-dom';

function FreelancerProfile() {
  // आपण सध्या डमी डेटा वापरत आहोत
  const freelancer = {
    name: "राहुल पाटील",
    title: "Full Stack Web Developer",
    location: "नाशिक, महाराष्ट्र",
    hourlyRate: "₹८०० / तास",
    about: "मी गेल्या ३ वर्षांपासून मॉडर्न वेब टेक्नॉलॉजीवर काम करत आहे. मला React, Node.js आणि UI/UX डिझाइनमध्ये विशेष आवड आहे. मी आतापर्यंत १० पेक्षा जास्त क्लायंटसाठी यशस्वीरित्या प्रोजेक्ट्स पूर्ण केले आहेत.",
    skills: ["React.js", "Node.js", "MongoDB", "Tailwind CSS", "Figma", "JavaScript"],
    experience: [
      { year: "२०२३ - चालू", role: "Senior Freelancer", company: "Upwork / Self-Employed" },
      { year: "२०२२ - २०२३", role: "Web Intern", company: "Tech Nashik Solutions" }
    ],
    projects: [
      { name: "E-commerce App", link: "#" },
      { name: "Portfolio Website", link: "#" }
    ]
  };

  return (
    <div className="profile-page bg-light min-vh-100 py-5">
      <div className="container">
        <div className="row g-4">
          
          {/* डावी बाजू: Profile Card */}
          <div className="col-lg-4">
            <div className="card border-0 shadow-sm rounded-4 p-4 text-center">
              <img 
                src="https://freepik.com" 
                className="rounded-circle border border-4 border-warning mx-auto mb-3" 
                style={{ width: '150px' }} 
                alt="Profile" 
              />
              <h3 className="fw-bold">{freelancer.name}</h3>
              <p className="text-primary fw-semibold">{freelancer.title}</p>
              <p className="text-muted small">📍 {freelancer.location}</p>
              <hr />
              <div className="d-flex justify-content-between px-3">
                <span className="text-muted">Rate:</span>
                <span className="fw-bold text-success">{freelancer.hourlyRate}</span>
              </div>
              <button className="btn btn-warning w-100 mt-4 fw-bold rounded-pill">Hire Me</button>
              <button className="btn btn-outline-dark w-100 mt-2 rounded-pill">Download CV</button>
            </div>
          </div>

          {/* उजवी बाजू: Details */}
          <div className="col-lg-8">
            {/* About Section */}
            <div className="card border-0 shadow-sm rounded-4 p-4 mb-4">
              <h4 className="fw-bold mb-3">About Me</h4>
              <p className="text-muted">{freelancer.about}</p>
            </div>

            {/* Skills Section */}
            <div className="card border-0 shadow-sm rounded-4 p-4 mb-4">
              <h4 className="fw-bold mb-3">Skills</h4>
              <div className="d-flex flex-wrap gap-2">
                {freelancer.skills.map((skill, index) => (
                  <span key={index} className="badge bg-primary px-3 py-2 rounded-pill">{skill}</span>
                ))}
              </div>
            </div>

            {/* Experience Section */}
            <div className="card border-0 shadow-sm rounded-4 p-4">
              <h4 className="fw-bold mb-3">Experience</h4>
              {freelancer.experience.map((exp, index) => (
                <div key={index} className="mb-3 pb-3 border-bottom">
                  <h6 className="fw-bold mb-0">{exp.role}</h6>
                  <small className="text-primary">{exp.company}</small>
                  <p className="text-muted small mb-0">{exp.year}</p>
                </div>
              ))}
            </div>
          </div>

        </div>
      </div>
    </div>
  );
}

export default FreelancerProfile;
